#include<cstdio>
#include<cstring>
#include<queue>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(b,c) for(int c=head[(b)];c;c=nxt[c])
namespace jr_zlw
{
	inline int read()
	{
		int res=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
		return flag ? -res : res ;
	}
	template<typename T> inline T min(T x,T y){return x<y?x:y;}
	template<typename T> inline T max(T x,T y){return x>y?x:y;}
	template<typename T> inline void swap(T x,T y){T tmp=x;x=y;y=tmp;}
	template<typename T> inline void rd(T &res)
	{
		res=0;char ch=getchar();bool flag=0;
		while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
		while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
		flag ? res = -res : 0 ;
	}
	const int N=1e6+10,M=2e6+10,INF=0x3f3f3f3f;int n,m;
	
	int head[N],des[M],val[M],nxt[M],cgt,dis1[N],disn[N],L[N],R[N],st[N],idx[N];bool vis[N],inp[N];
	inline void ins(int x,int y,int z){nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;}
	struct Sort
	{
		int idx,val;inline Sort(int xx=0,int yy=0){idx=xx;val=yy;}
		inline bool operator < (const Sort &Q)const{return val>Q.val;}
	};std::priority_queue<Sort> h;
	inline void dij(int s,int *dis)
	{
		memset(dis+1,0x3f,n<<2);memset(vis+1,0,n);
		h.push(Sort(s,dis[s]=0));while(!h.empty())
		{
			int u=h.top().idx;h.pop();if(vis[u])continue;vis[u]=1;
			grep(u,i){int v=des[i];if(dis[u]+val[i]<dis[v]){dis[v]=dis[u]+val[i];h.push(Sort(v,dis[v]));}}
		}
	}
	int que[N],H,T;inline void bfs(int x,int *dis,int *qwq)
	{
		qwq[que[H=T=1]=st[x]]=x;
		while(H<=T){int u=que[H++];grep(u,i){int v=des[i];if(!idx[v]&&!qwq[v]&&dis[u]+val[i]==dis[v])qwq[que[++T]=v]=x;}}
	}
	
	int mn[N<<2],mnn[N],cnt;
	inline void pushdown(int l=1,int r=cnt,int cur=1)
	{
		if(l==r){mnn[l]=mn[cur];return;}int mid=(l+r)>>1;
		mn[cur<<1]=min(mn[cur<<1],mn[cur]);mn[cur<<1|1]=min(mn[cur<<1|1],mn[cur]);
		pushdown(l,mid,cur<<1);pushdown(mid+1,r,cur<<1|1);return; 
	}
	inline void add(int ql,int qr,int w,int l=1,int r=cnt,int cur=1)
	{
		if(ql<=l&&r<=qr){mn[cur]=min(mn[cur],w);return;}int mid=(l+r)>>1;
		if(ql<=mid)add(ql,qr,w,l,mid,cur<<1);if(qr>mid)add(ql,qr,w,mid+1,r,cur<<1|1);
	}
	inline void mian()
	{
		rd(n);rd(m);memset(mn,0x3f,sizeof(mn));
		rep(1,m,i){int x=read(),y=read(),z=read();ins(x,y,z);ins(y,x,z);}
		dij(1,dis1);dij(n,disn);int u=1;
		while(u^n)
		{
			st[++cnt]=u;idx[u]=cnt;
			grep(u,i){int v=des[i];if(disn[v]+val[i]==disn[u]){inp[i]=1;u=v;break;}}
		}
		st[++cnt]=n;idx[n]=cnt;rep(1,cnt,i)bfs(i,dis1,L),bfs(i,disn,R);--cnt;
		rep(1,n,u)grep(u,i){int v=des[i];if(!inp[i]&&L[u]<R[v])add(L[u],R[v]-1,dis1[u]+val[i]+disn[v]);}
		pushdown();int num=0;rep(1,n,i){if(mnn[i]>u)u=mnn[i],num=0;if(mnn[i]==u)++num;}
		if(u==dis1[n])num=m;printf("%d %d\n",u,num);return;
	}
}
int main(){jr_zlw::mian();return 0;}
